52: func expandConfig(file *ini.File) error {
53: 	sort.Slice(expanders, func(i, j int) bool {
54: 		return expanders[i].priority < expanders[j].priority
55: 	})
56: 
57: 	for _, expander := range expanders {
58: 		err := expander.expander.SetupExpander(file)
59: 		if err != nil {
60: 			return fmt.Errorf("got error during initialization of expander '%s': %w", expander.name, err)
61: 		}
62: 
63: 		for _, section := range file.Sections() {
64: 			for _, key := range section.Keys() {
65: 				updated, err := applyExpander(key.Value(), expander)
66: 				if err != nil {
67: 					return fmt.Errorf("got error while expanding %s.%s with expander '%s': %w",
68: 						section.Name(),
69: 						key.Name(),
70: 						expander.name,
71: 						err)
72: 				}
73: 
74: 				key.SetValue(updated)
75: 			}
76: 		}
77: 	}
78: 	return nil
79: }
