17: //
18: // Fetch settings.
19: //
20: // If you are running Grafana Enterprise and have Fine-grained access control enabled, you need to have a permission with action `settings:read` and scopes: `settings:*`, `settings:auth.saml:` and `settings:auth.saml:enabled` (property level).
21: //
22: // Security:
23: // - basic:
24: //
25: // Responses:
26: // 200: adminGetSettingsResponse
27: // 401: unauthorisedError
28: // 403: forbiddenError
29: func (hs *HTTPServer) AdminGetSettings(c *contextmodel.ReqContext) response.Response {
30: 	settings, err := hs.getAuthorizedSettings(c.Req.Context(), c.SignedInUser, hs.SettingsProvider.Current())
31: 	if err != nil {
32: 		return response.Error(http.StatusForbidden, "Failed to authorize settings", err)
33: 	}
34: 	return response.JSON(http.StatusOK, settings)
35: }
